from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Group triples by subject
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Find the main subject (politician)
    main_subject = None
    for subj in subject_triples:
        for t in subject_triples[subj]:
            if t.predicate in ["profession", "office", "party", "nationality", "birthPlace"]:
                main_subject = subj
                break
        if main_subject:
            break

    if not main_subject:
        main_subject = list(subject_triples.keys())[0] if subject_triples else ""

    main_triples = subject_triples.get(main_subject, [])

    # Organize information by category
    birth_info = []
    personal_info = []
    career_info = []
    other_info = []

    for t in main_triples:
        if t.predicate in ["birthPlace", "birthDate", "birthYear"]:
            birth_info.append(t)
        elif t.predicate in ["deathPlace", "deathDate", "deathYear", "spouse", "residence", "nationality", "religion"]:
            personal_info.append(t)
        elif t.predicate in ["office", "party", "successor", "predecessor", "inOfficeWhilePresident",
                            "inOfficeWhilePrimeMinister", "inOfficeWhileVicePresident",
                            "inOfficeWhileGovernor", "inOfficeWhileMonarch"]:
            career_info.append(t)
        else:
            other_info.append(t)

    # Build sentence parts
    parts = []

    # Birth information
    if birth_info:
        birth_parts = []
        for t in birth_info:
            if t.predicate == "birthPlace":
                birth_parts.append(f"born in {t.object}")
            elif t.predicate in ["birthDate", "birthYear"]:
                birth_parts.append(f"born in {t.object}")
        if birth_parts:
            parts.append(f"{main_subject} was {' and '.join(birth_parts)}")

    # Personal information
    if personal_info:
        personal_parts = []
        for t in personal_info:
            if t.predicate == "nationality":
                personal_parts.append(f"of {t.object} nationality")
            elif t.predicate == "spouse":
                personal_parts.append(f"married to {t.object}")
            elif t.predicate == "residence":
                personal_parts.append(f"residing in {t.object}")
            elif t.predicate == "religion":
                personal_parts.append(f"of {t.object} faith")
        if personal_parts:
            if not parts:
                parts.append(f"{main_subject} {' and '.join(personal_parts)}")
            else:
                parts.append(f"who is {' and '.join(personal_parts)}")

    # Career information
    if career_info:
        career_parts = []
        for t in career_info:
            if t.predicate == "office":
                career_parts.append(f"held the office of {t.object}")
            elif t.predicate == "party":
                career_parts.append(f"was a member of the {t.object} party")
            elif t.predicate == "successor":
                career_parts.append(f"was succeeded by {t.object}")
            elif t.predicate == "predecessor":
                career_parts.append(f"was preceded by {t.object}")
            elif t.predicate == "inOfficeWhilePresident":
                career_parts.append(f"served while {t.object} was president")
            elif t.predicate == "inOfficeWhilePrimeMinister":
                career_parts.append(f"served while {t.object} was prime minister")
            elif t.predicate == "inOfficeWhileVicePresident":
                career_parts.append(f"served while {t.object} was vice president")
        if career_parts:
            if not parts:
                parts.append(f"{main_subject} {' and '.join(career_parts)}")
            else:
                parts.append(f"who {' and '.join(career_parts)}")

    # Combine all parts into one complex sentence
    if len(parts) == 1:
        return parts[0]
    elif len(parts) == 2:
        return parts[0] + " " + parts[1]
    else:
        # Join with commas and final "and"
        return ", ".join(parts[:-1]) + " and " + parts[-1] if len(parts) > 1 else parts[0]

# EVOLVE-BLOCK-END
